package store

import (
	"context"
	"errors"
	"fmt"
	"os"
	"strings"
	"sync"
	"time"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

var (
	ErrNotFound = errors.New("store: not found")
)

type Store interface {
	Ping(ctx context.Context) error
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error)
	StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error
	UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error)
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error)
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error
	Close()
}

var (
	storeInstance Store
	once          sync.Once
)

func Storage() Store {
	once.Do(func() {
		storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
		if storeType == "" {
			storeType = "redis"
		}

		var err error
		switch storeType {
		case "redis":
			storeInstance, err = NewRedisStore()
			if err != nil {
				klog.Fatalf("Failed to initialize Redis store: %v", err)
			}
		case "valkey":
			klog.Fatalf("Valkey support not yet implemented")
		default:
			klog.Fatalf("Unsupported store type: %s (supported: redis, valkey)", storeType)
		}

		if err != nil {
			klog.Fatalf("Failed to initialize store: %v", err)
		}
	})
	return storeInstance
}

func sessionKey(sessionID string) string {
	return fmt.Sprintf("session:%s", sessionID)
}

const (
	ExpiryIndexKey       = "session:expiry"
	LastActivityIndexKey = "session:last_activity"
)

