package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	SessionHeader        = "x-agentcube-session-id"
	RouterIdentitySecret = "picod-router-identity"
	PrivateKeyKey        = "private.pem"
	PublicKeyKey         = "public.pem"
)

type ServerConfig struct {
	Port                  int
	WorkloadManagerURL    string
	MaxConcurrentRequests int
	EnableTLS             bool
	TLSCertFile           string
	TLSKeyFile            string
}

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
}

func NewJWTManager() *JWTManager {
	return &JWTManager{}
}

func (j *JWTManager) TryStoreOrLoadJWTKeySecret(namespace string) error {
	if namespace == "" {
		namespace = os.Getenv("AGENTCUBE_NAMESPACE")
		if namespace == "" {
			namespace = "default"
		}
	}

	config, err := rest.InClusterConfig()
	if err != nil {
		klog.V(4).Infof("Not running in cluster, skipping JWT secret creation: %v", err)
		return nil
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return fmt.Errorf("failed to create clientset: %w", err)
	}

	secret, err := clientset.CoreV1().Secrets(namespace).Get(context.Background(), RouterIdentitySecret, metav1.GetOptions{})
	if err == nil {
		privateKeyBlock, _ := pem.Decode(secret.Data[PrivateKeyKey])
		publicKeyBlock, _ := pem.Decode(secret.Data[PublicKeyKey])

		if privateKeyBlock == nil || publicKeyBlock == nil {
			return fmt.Errorf("invalid PEM data in secret")
		}

		j.privateKey, err = x509.ParsePKCS1PrivateKey(privateKeyBlock.Bytes)
		if err != nil {
			return fmt.Errorf("failed to parse private key: %w", err)
		}

		j.publicKey, err = x509.ParsePKCS1PublicKey(publicKeyBlock.Bytes)
		if err != nil {
			return fmt.Errorf("failed to parse public key: %w", err)
		}

		klog.V(4).Infof("Loaded existing JWT key secret")
		return nil
	}

	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return fmt.Errorf("failed to generate private key: %w", err)
	}

	publicKey := &privateKey.PublicKey

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(publicKey),
	})

	secret = &v1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      RouterIdentitySecret,
			Namespace: namespace,
		},
		Data: map[string][]byte{
			PrivateKeyKey: privateKeyPEM,
			PublicKeyKey:  publicKeyPEM,
		},
	}

	_, err = clientset.CoreV1().Secrets(namespace).Create(context.Background(), secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create secret: %w", err)
	}

	j.privateKey = privateKey
	j.publicKey = publicKey

	klog.Infof("Created new JWT key secret in namespace %s", namespace)
	return nil
}

func (j *JWTManager) GenerateToken(sessionID string, kind string) (string, error) {
	claims := jwt.MapClaims{
		"sub": sessionID,
		"kind": kind,
		"exp": time.Now().Add(24 * time.Hour).Unix(),
		"iat": time.Now().Unix(),
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) GetPublicKey() *rsa.PublicKey {
	return j.publicKey
}

type SessionManager struct {
	workloadManagerURL string
	httpClient         *http.Client
	store              store.Store
}

func NewSessionManager(workloadManagerURL string) (*SessionManager, error) {
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	return &SessionManager{
		workloadManagerURL: strings.TrimSuffix(workloadManagerURL, "/"),
		httpClient: &http.Client{
			Timeout: 30 * time.Second,
		},
		store: store.Storage(),
	}, nil
}

func (sm *SessionManager) GetSandboxBySession(ctx context.Context, sessionID string, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		return nil, api.NewSessionNotFoundError("")
	}

	sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil, api.NewSessionNotFoundError(sessionID)
		}
		return nil, err
	}

	return sandbox, nil
}

func (sm *SessionManager) CreateSandbox(ctx context.Context, kind, name, namespace string) (*types.SandboxInfo, error) {
	createReq := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	reqBody, err := json.Marshal(createReq)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal create request: %w", err)
	}

	url := fmt.Sprintf("%s/v1/%s", sm.workloadManagerURL, strings.ToLower(kind))
	if kind == types.AgentRuntimeKind {
		url = fmt.Sprintf("%s/v1/agent-runtime", sm.workloadManagerURL)
	} else if kind == types.CodeInterpreterKind {
		url = fmt.Sprintf("%s/v1/code-interpreter", sm.workloadManagerURL)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(reqBody))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	tokenPath := "/var/run/secrets/kubernetes.io/serviceaccount/token"
	if tokenData, err := os.ReadFile(tokenPath); err == nil {
		token := strings.TrimSpace(string(tokenData))
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := sm.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("failed to call workload manager: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		if resp.StatusCode == http.StatusNotFound {
			return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
		}
		return nil, fmt.Errorf("workload manager returned status %d", resp.StatusCode)
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("empty session ID in response")
	}

	sandboxInfo := &types.SandboxInfo{
		Kind:        kind,
		SandboxID:   createResp.SandboxID,
		Name:        createResp.SandboxName,
		SessionID:   createResp.SessionID,
		EntryPoints: createResp.EntryPoints,
		Status:      "running",
		CreatedAt:   time.Now(),
		ExpiresAt:   time.Now().Add(8 * time.Hour),
	}

	if err := sm.store.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, fmt.Errorf("failed to store sandbox: %w", err)
	}

	return sandboxInfo, nil
}

