package main

import (
	"flag"
	"fmt"
	"os"
	"time"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	port := 8080
	if p := os.Getenv("WORKLOAD_MANAGER_PORT"); p != "" {
		fmt.Sscanf(p, "%d", &port)
	}

	enableAuth := os.Getenv("ENABLE_AUTH") == "true"
	enableTLS := os.Getenv("ENABLE_TLS") == "true"
	tlsCertFile := os.Getenv("TLS_CERT_FILE")
	tlsKeyFile := os.Getenv("TLS_KEY_FILE")

	config := &workloadmanager.ServerConfig{
		Port:        port,
		EnableAuth:  enableAuth,
		EnableTLS:   enableTLS,
		TLSCertFile: tlsCertFile,
		TLSKeyFile:  tlsKeyFile,
		ReadTimeout: 15 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	server, err := workloadmanager.NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	klog.Infof("Starting Workload Manager on port %d", port)
	if err := server.Start(); err != nil {
		klog.Fatalf("Server failed: %v", err)
	}
}

